function mergeKSortedLists(data) {
    const lines = data.trim().split('\n');
    const k = parseInt(lines[0]);
    let mergedList = [];

    for (let i = 1; i <= k; i++) {
        const list = lines[i].trim().split(' ').map(Number);
        mergedList = mergedList.concat(list);
    }

    mergedList.sort((a, b) => a - b);
    return mergedList.join(' ');
}

