#include <vector>
#include <string>
#include <queue>
using namespace std;
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {
    }
}
;
class Solution {
    public:
    ListNode* mergeKSortedLists(vector<ListNode*>& data) {
        auto cmp = [](ListNode* a, ListNode* b) {
            return a->val > b->val;
        }
        ;
        priority_queue<ListNode*, vector<ListNode*>, decltype(cmp)> minHeap(cmp);
        for (ListNode* node : data) {
            if (node) {
                minHeap.push(node);
            }
        }
        ListNode dummy(0);
        ListNode* tail = &dummy;
        while (!minHeap.empty()) {
            ListNode* minNode = minHeap.top();
            minHeap.pop();
            tail->next = minNode;
            tail = tail->next;
            if (minNode->next) {
                minHeap.push(minNode->next);
            }
        }
        return dummy.next;
    }
}
